import style from "./index.module.scss"
import template from './index.html'

let progressId = 0
let progressDescriptionId = 0
export default class Progress extends HTMLElement {
  set value(value: string) {
    this.setAttribute("value", value)
    this.progressEle.setAttribute("value", value)
  }
  get value(): string {
    return this.getAttribute("value") || ""
  }
  set max(value: string) {
    this.setAttribute("max", value)
    this.progressEle.setAttribute("max", value)
  }
  get max(): string {
    return this.getAttribute("max") || ""
  }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ["value", "max"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  willLoad = () => {
    this.labelEle = this.shadowRoot?.querySelector("label")
    this.progressEle = this.shadowRoot?.querySelector("progress")
    this.descriptionEle = this.shadowRoot?.querySelector("div")
    const id = `progress-label-${++progressId}`
    const descriptionId = `progress-description-${++progressDescriptionId}`
    this.progressEle.setAttribute("id", id)
    this.progressEle.setAttribute("aria-describedby", descriptionId)
    this.labelEle.setAttribute("for", id)
    this.descriptionEle.setAttribute("id", descriptionId)
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.willLoad()
    this.render()
  }
  disconnectedCallback() {
  }

  render = () => {
    this.max && this.progressEle?.setAttribute("max", this.max)
    this.value && this.progressEle?.setAttribute("value", this.value)
  }
}
